    std::vector<uint32_t> Encode(const std::string& text) {
        std::vector<uint32_t> tokens;
        
        // 1. Byte-level split (naive UTF-8 handling)
        std::vector<std::string> word;
        for (char c : text) {
            word.push_back(std::string(1, c));
        }

        // 2. BPE Merge Loop
        while (word.size() > 1) {
            // Find best pair to merge
            int bestIdx = -1;
            size_t bestRank = SIZE_MAX;

            for (size_t i = 0; i < word.size() - 1; i++) {
                std::string pair = word[i] + word[i+1];
                // Check if pair exists in vocab/merges
                // In a real optimized engine, we use the rank map here
                // For simplicity: linear scan of merges is O(N*M), slow but functional.
                // Replaced with hypothetical O(1) lookup:
                size_t rank = GetMergeRank(word[i], word[i+1]);
                
                if (rank < bestRank) {
                    bestRank = rank;
                    bestIdx = i;
                }
            }

            if (bestIdx == -1) break; // No more merges possible

            // Perform merge
            word[bestIdx] = word[bestIdx] + word[bestIdx+1];
            word.erase(word.begin() + bestIdx + 1);
        }

        // 3. Map to IDs
        tokens.push_back(BOS_ID);
