#include <windows.h>
#include "rawrxd_inference_core.cpp"
#include "rawrxd_renderer_d2d.cpp"
#include "rawrxd_agent_bridge.h"

// Globals
SPSCQueue<AgentTask, 1024> g_AgentInputQueue;
SPSCQueue<AgentResponse, 4096> g_AgentOutputQueue;
RawrXDEditorRenderer g_Renderer;

// The Agent Thread
void AgentThreadProc() {
    RawrXDInferenceEngine engine;
    engine.Initialize("models/RawrXD-7B.gguf");

    // Hook up callback to push to SPSC queue
    engine.onTokenGenerated = [](const std::string& token) {
        g_AgentOutputQueue.Push({token, false});
    };

    while (true) {
        auto task = g_AgentInputQueue.Pop();
        if (task) {
            if (task->type == AgentTask::INFERENCE_REQ) {
                engine.Generate(task->payload, 2048);
                g_AgentOutputQueue.Push({"", true}); // Done signal
            }
        }
        std::this_thread::sleep_for(std::chrono::milliseconds(1)); // Yield
    }
}

// Main Window Loop
LRESULT CALLBACK WndProc(HWND hwnd, UINT msg, WPARAM wp, LPARAM lp) {
    if (msg == WM_PAINT) {
        // Drain SPSC queue into internal text buffer
        static std::string editorContent = "// RawrXD Ready.\n";
        while (auto resp = g_AgentOutputQueue.Pop()) {
            editorContent += resp->tokenChunk;
        }
        
        // Render
        g_Renderer.RenderText(editorContent, 0.0f);
        return 0;
    }
    // ... Input handling to push to g_AgentInputQueue ...
    return DefWindowProc(hwnd, msg, wp, lp);
}

int WINAPI WinMain(HINSTANCE hInst, HINSTANCE, LPSTR, int) {
    // 1. Create Window
    // 2. Init Renderer
    // 3. Start Agent Thread
    std::thread agent(AgentThreadProc);
    agent.detach();
    
    // 4. Message Loop (144Hz timer triggers WM_PAINT)
    // ...
}

